func (this *BitgetCore) ParseLedgerEntry(item any, optionalArgs ...any) any {
	//
	// spot
	//
	//     {
	//         "billId": "1111506298997215233",
	//         "coin": "USDT",
	//         "groupType": "transfer",
	//         "businessType": "transfer_out",
	//         "size": "-11.64958799",
	//         "balance": "0.00000000",
	//         "fees": "0.00000000",
	//         "cTime": "1700729673028"
	//     }
	//
	// swap and future
	//
	//     {
	//         "billId": "1111499428100472833",
	//         "symbol": "",
	//         "amount": "-11.64958799",
	//         "fee": "0",
	//         "feeByCoupon": "",
	//         "businessType": "trans_to_exchange",
	//         "coin": "USDT",
	//         "cTime": "1700728034996"
	//     }
	//
	currency := GetArg(optionalArgs, 0, nil)
	_ = currency
	var currencyId any = this.SafeString(item, "coin")
	var code any = this.SafeCurrencyCode(currencyId, currency)
	currency = this.SafeCurrency(currencyId, currency)
	var timestamp any = this.SafeInteger(item, "cTime")
	var after any = this.SafeNumber(item, "balance")
	var fee any = this.SafeNumber2(item, "fees", "fee")
	var amountRaw any = this.SafeString2(item, "size", "amount")
	var amount any = this.ParseNumber(Precise.StringAbs(amountRaw))
	var direction any = "in"
	if IsTrue(IsGreaterThanOrEqual(GetIndexOf(amountRaw, "-"), 0)) {
		direction = "out"
	}
	return this.SafeLedgerEntry(map[string]any{
		"info":             item,
		"id":               this.SafeString(item, "billId"),
		"timestamp":        timestamp,
		"datetime":         this.Iso8601(timestamp),
		"direction":        direction,
		"account":          nil,
		"referenceId":      nil,
		"referenceAccount": nil,
		"type":             this.ParseLedgerType(this.SafeString(item, "businessType")),
		"currency":         code,
		"amount":           amount,
		"before":           nil,
		"after":            after,
		"status":           nil,
		"fee": map[string]any{
			"currency": code,
			"cost":     fee,
		},
	}, currency)
}
