func (this *BitgetCore) ParseMarginLoan(info any, optionalArgs ...any) any {
	//
	// isolated: borrowMargin
	//
	//     {
	//         "loanId": "1112125304879067137",
	//         "symbol": "BTCUSDT",
	//         "coin": "USDT",
	//         "borrowAmount": "4"
	//     }
	//
	// cross: borrowMargin
	//
	//     {
	//         "loanId": "1112122013642272769",
	//         "coin": "USDT",
	//         "borrowAmount": "4"
	//     }
	//
	// isolated: repayMargin
	//
	//     {
	//         "remainDebtAmount": "0",
	//         "repayId": "1112126405439270912",
	//         "symbol": "BTCUSDT",
	//         "coin": "USDT",
	//         "repayAmount": "8.000137"
	//     }
	//
	// cross: repayMargin
	//
	//     {
	//         "remainDebtAmount": "0",
	//         "repayId": "1112122994945830912",
	//         "coin": "USDT",
	//         "repayAmount": "4.00006834"
	//     }
	//
	currency := GetArg(optionalArgs, 0, nil)
	_ = currency
	market := GetArg(optionalArgs, 1, nil)
	_ = market
	var currencyId any = this.SafeString(info, "coin")
	var marketId any = this.SafeString(info, "symbol")
	var symbol any = nil
	if IsTrue(!IsEqual(marketId, nil)) {
		symbol = this.SafeSymbol(marketId, market, nil, "spot")
	}
	return map[string]any{
		"id":        this.SafeString2(info, "loanId", "repayId"),
		"currency":  this.SafeCurrencyCode(currencyId, currency),
		"amount":    this.SafeNumber2(info, "borrowAmount", "repayAmount"),
		"symbol":    symbol,
		"timestamp": nil,
		"datetime":  nil,
		"info":      info,
	}
}

